import{_ as n,o as r,c as t,ag as i}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Unternehmen einrichten","description":"","frontmatter":{},"headers":[],"relativePath":"de/getting-started/company-setup.md","filePath":"de/getting-started/company-setup.md"}'),a={name:"de/getting-started/company-setup.md"};function s(l,e,o,d,h,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="unternehmen-einrichten" tabindex="-1">Unternehmen einrichten <a class="header-anchor" href="#unternehmen-einrichten" aria-label="Permalink to &quot;Unternehmen einrichten&quot;">​</a></h1><p>Bevor Sie Rechnungen versenden können, müssen Sie Ihre Unternehmensinformationen konfigurieren. Diese Daten erscheinen auf Ihren Rechnungen, Angeboten und anderen Dokumenten.</p><h2 id="unternehmensinformationen" tabindex="-1">Unternehmensinformationen <a class="header-anchor" href="#unternehmensinformationen" aria-label="Permalink to &quot;Unternehmensinformationen&quot;">​</a></h2><p>Navigieren Sie zu <strong>Unternehmen</strong> in der Seitenleiste, um auf Ihre Unternehmenseinstellungen zuzugreifen.</p><h3 id="pflichtfelder" tabindex="-1">Pflichtfelder <a class="header-anchor" href="#pflichtfelder" aria-label="Permalink to &quot;Pflichtfelder&quot;">​</a></h3><p>Diese Felder werden zum Versenden von Rechnungen benötigt:</p><ul><li><strong>Firmenname</strong> — Ihr eingetragener Firmenname</li><li><strong>Adresse</strong> — Straße, Postleitzahl und Stadt (Adress-Autovervollständigung ist verfügbar)</li><li><strong>E-Mail</strong> — Ihre geschäftliche Kontakt-E-Mail</li></ul><h3 id="empfohlene-felder" tabindex="-1">Empfohlene Felder <a class="header-anchor" href="#empfohlene-felder" aria-label="Permalink to &quot;Empfohlene Felder&quot;">​</a></h3><p>Diese werden für professionelle Rechnungen und die rechtliche Konformität dringend empfohlen:</p><ul><li><strong>USt.-Nummer</strong> — Ihre Umsatzsteuer-Identifikationsnummer (z. B. NL123456789B01)</li><li><strong>Handelsregisternummer</strong> — Ihre Gewerbeanmeldungsnummer</li><li><strong>IBAN</strong> — Ihre Bankkontonummer, auf die Kunden zahlen sollen</li><li><strong>Telefonnummer</strong> — Geschäftliche Kontakttelefonnummer</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>In vielen Ländern sind USt.-Nummer und Registrierungsnummer auf Rechnungen gesetzlich vorgeschrieben. Stellen Sie sicher, dass diese ausgefüllt sind, bevor Sie Ihre erste Rechnung versenden.</p></div><h2 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h2><h3 id="firmenlogo" tabindex="-1">Firmenlogo <a class="header-anchor" href="#firmenlogo" aria-label="Permalink to &quot;Firmenlogo&quot;">​</a></h3><p>Laden Sie Ihr Firmenlogo hoch, damit es erscheint auf:</p><ul><li>Rechnungen und Angeboten (PDF)</li><li>E-Mail-Kommunikation</li><li>Ihrer öffentlichen Geschäftsseite</li><li>Dem Kundenzahlungsportal</li></ul><p>Unterstützte Formate: PNG, JPG, SVG. Für beste Ergebnisse verwenden Sie ein hochauflösendes Bild mit transparentem Hintergrund.</p><h3 id="farbschema" tabindex="-1">Farbschema <a class="header-anchor" href="#farbschema" aria-label="Permalink to &quot;Farbschema&quot;">​</a></h3><p>Passen Sie die Akzentfarbe an, die auf Ihren Rechnungen und Dokumenten verwendet wird, um sie an Ihre Markenidentität anzupassen.</p><h2 id="finanzielle-standardeinstellungen" tabindex="-1">Finanzielle Standardeinstellungen <a class="header-anchor" href="#finanzielle-standardeinstellungen" aria-label="Permalink to &quot;Finanzielle Standardeinstellungen&quot;">​</a></h2><p>Richten Sie Standardwerte ein, die für neue Rechnungen und Angebote gelten:</p><ul><li><strong>Währung</strong> — Ihre Standardwährung (standardmäßig EUR)</li><li><strong>Zahlungsbedingungen</strong> — Standard-Anzahl der Tage bis zur Fälligkeit einer Rechnung (z. B. 14 oder 30 Tage)</li><li><strong>Rechnungsnummerierung</strong> — Passen Sie das Format Ihrer Rechnungsnummern an <ul><li>Präfix (z. B. <code>INV-</code> oder <code>2024-</code>)</li><li>Startnummer</li><li>Automatische Erhöhung</li></ul></li></ul><h3 id="beispiele-fur-rechnungsnummerierung" tabindex="-1">Beispiele für Rechnungsnummerierung <a class="header-anchor" href="#beispiele-fur-rechnungsnummerierung" aria-label="Permalink to &quot;Beispiele für Rechnungsnummerierung&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Format</th><th>Beispiel</th></tr></thead><tbody><tr><td>Einfach</td><td><code>001</code>, <code>002</code>, <code>003</code></td></tr><tr><td>Mit Präfix</td><td><code>INV-001</code>, <code>INV-002</code></td></tr><tr><td>Jahresbasiert</td><td><code>2024-001</code>, <code>2024-002</code></td></tr></tbody></table><p>Die Nummerierungsoptionen und das Format können jederzeit angepasst werden. Bestehende Rechnungsnummern werden nie geändert.</p><h2 id="pdf-vorlage" tabindex="-1">PDF-Vorlage <a class="header-anchor" href="#pdf-vorlage" aria-label="Permalink to &quot;PDF-Vorlage&quot;">​</a></h2><p>MyCompanyDesk generiert automatisch professionelle PDF-Rechnungen. Sie können das Layout mit dem <strong>PDF-Editor</strong> anpassen:</p><ul><li>Feldpositionen und Sichtbarkeit anpassen</li><li>Wählen, welche Informationen angezeigt werden</li><li>Schriftarten und Größen anpassen</li><li>Änderungen in Echtzeit mit einer Musterrechnung in der Vorschau ansehen</li></ul><p>Greifen Sie auf den PDF-Editor über <strong>Unternehmen &gt; PDF-Editor</strong> oder über den Branding-Bereich zu.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>PDF-Anpassungen über die Grundeinstellungen hinaus erfordern den <strong>Pro</strong>-Tarif oder höher.</p></div><h2 id="funktionsumschalter" tabindex="-1">Funktionsumschalter <a class="header-anchor" href="#funktionsumschalter" aria-label="Permalink to &quot;Funktionsumschalter&quot;">​</a></h2><p>MyCompanyDesk verfügt über optionale Module, die Sie je nach Ihren Geschäftsanforderungen aktivieren oder deaktivieren können:</p><ul><li><strong>Objekte / Vermögenswerte</strong> — Für Mietobjekt- und Vermögensverwaltung</li><li><strong>Verträge</strong> — Für wiederkehrende Dienstleistungs- oder Mietverträge</li><li><strong>Projekte</strong> — Für projektbasierte Arbeit und Zeiterfassung</li><li><strong>Angebote</strong> — Für das Versenden von Kostenvoranschlägen</li><li><strong>Reverse-Charge</strong> — Für innergemeinschaftliche B2B-Transaktionen</li><li><strong>KI-Vorschläge</strong> — Für intelligente Kategorisierung und Empfehlungen</li><li><strong>Belegscanner</strong> — Für OCR-basierte Ausgabenerfassung</li><li><strong>Textprüfung</strong> — Für Grammatik- und Rechtschreibprüfung in Ihren Dokumenten</li></ul><p>Das Deaktivieren eines Moduls blendet es in der Navigation aus und hält Ihren Arbeitsbereich übersichtlich und fokussiert.</p><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Ihr Unternehmen ist eingerichtet. Zeit, <a href="/de/getting-started/first-invoice">Ihre erste Rechnung zu erstellen</a>.</p>',35)])])}const m=n(a,[["render",s]]);export{c as __pageData,m as default};
